mapper.select:
SELECT FROM train_plan p LEFT JOIN train_project pr ON p.project_id = pr.id LEFT JOIN sys_user u ON p.teacher_id = u.id
AND p.plan_name LIKE CONCAT('%', #{planName}, '%') AND p.term_year LIKE CONCAT('%', #{termYear}, '%') AND p.plan_status = #{planStatus}
ORDER BY p.create_time DESC

mapper.update:
UPDATE train_plan
project_id = #{projectId}, plan_name = #{planName}, term_year = #{termYear}, start_date = #{startDate}, end_date = #{endDate}, train_address = #{trainAddress}, teacher_id = #{teacherId}, second_teacher_id = #{secondTeacherId}, max_student = #{maxStudent}, enroll_num = #{enrollNum}, enroll_start = #{enrollStart}, enroll_end = #{enrollEnd}, plan_status = #{planStatus}, remark = #{remark}, update_time = #{updateTime},
WHERE id = #{id}
